import { useEffect, useState } from "react";
import { getPatients, addPatient, getAppointments, addAppointment } from "../api";

export default function Dashboard() {
  const [patients, setPatients] = useState([]);
  const [appointments, setAppointments] = useState([]);

  const [p, setP] = useState({ name: "", phone: "", age: "" });
  const [a, setA] = useState({ patient_id: "", doctor_id: "", date: "" });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setPatients(await getPatients());
    setAppointments(await getAppointments());
  };

  const addP = async () => {
    await addPatient({
      name: p.name,
      phone: p.phone,
      age: parseInt(p.age)
    });
    setP({ name: "", phone: "", age: "" });
    loadData();
  };

  const addA = async () => {
    await addAppointment({
      patient_id: parseInt(a.patient_id),
      doctor_id: parseInt(a.doctor_id),
      date: a.date
    });
    setA({ patient_id: "", doctor_id: "", date: "" });
    loadData();
  };

  return (
    <div>
      <h2>Doctor Dashboard</h2>

      <h3>Add Patient</h3>
      <input placeholder="Name" onChange={e=>setP({...p,name:e.target.value})}/>
      <input placeholder="Phone" onChange={e=>setP({...p,phone:e.target.value})}/>
      <input placeholder="Age" onChange={e=>setP({...p,age:e.target.value})}/>
      <button onClick={addP}>Add</button>

      <h3>Patients</h3>
      {patients.map(p => <div key={p.id}>{p.name}</div>)}

      <h3>Add Appointment</h3>
      <input placeholder="Patient ID" onChange={e=>setA({...a,patient_id:e.target.value})}/>
      <input placeholder="Doctor ID" onChange={e=>setA({...a,doctor_id:e.target.value})}/>
      <input type="datetime-local" onChange={e=>setA({...a,date:e.target.value})}/>
      <button onClick={addA}>Add</button>

      <h3>Appointments</h3>
      {appointments.map(a => <div key={a.id}>{a.date}</div>)}
    </div>
  );
}
